    // Flash screen red on death
    var alpha = Math.min(1, e.respawnTimer / 60);
    ctx.fillStyle = 'rgba(255,0,0,' + (alpha * 0.5) + ')';
    ctx.fillRect(0, 0, W, H);

    // Draw death message
    if (e.respawnTimer > 0) {
      ctx.save();
      ctx.globalAlpha = Math.min(1, e.respawnTimer / 40);
      ctx.fillStyle = '#ff2244';
      ctx.font = 'bold ' + Math.floor(48 + Math.sin(g.tick * 0.1) * 4) + 'px monospace';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.shadowColor = '#ff0000';
      ctx.shadowBlur = 30;
      ctx.fillText('ABSORBED', W / 2, H / 2 - 30);
      ctx.font = '22px monospace';
      ctx.fillStyle = '#ff8888';
      ctx.shadowBlur = 10;
      ctx.fillText('respawning...', W / 2, H / 2 + 20);
      ctx.restore();
    }

    if (e.respawnTimer <= 0) {
      e.dead = false;
      e.list = [];
      e.spawnTimer = 0;
