        // Attraction force: stronger at edge, slingshot feel
        var factor = (1 - dist / fieldR);
        var force = pullStrength * factor * factor * 3.5;
        var nx = dx / dist;
        var ny = dy / dist;

        p.vx = (p.vx || 0) + nx * force * 0.016;
        p.vy = (p.vy || 0) + ny * force * 0.016;

        // Clamp particle velocity
